queries.sparql:
PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?default_subtitle WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSubtitles ?child ; p:hasStreaming_Services ?parent . } GROUP BY ?child }
  ?child p:default_subtitle ?default_subtitle .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Streaming_Services } }
  FILTER(?nf = ?total)
}

